// ── helpers ──────────────────────────────────────────────────────────────────

// safeID converts a capability ID to a CSS-safe string for use in id attributes
// and hx-target selectors. Colons, slashes, and dots are all invalid in unquoted
// CSS ID selectors used by HTMX's hx-target.
func safeID(id string) string {
	r := strings.NewReplacer(":", "-", "/", "-", ".", "-")
	return r.Replace(id)
}

func cardClass(dec storage.VerificationDecision) string {
	if dec.ID == "" {
		return "cap-card"
	}
	if string(dec.Decision) == "confirm" {
		return "cap-card decided confirmed"
	}
	return "cap-card decided reverted"
}

func progressPct(decided, total int) int {
	if total == 0 {
		return 100
	}
	return decided * 100 / total
}

func plural(n int, singular, pluralForm string) string {
	if n == 1 {
		return singular
	}
	return pluralForm
}

